const lead = $input.first().json;

// Extract fields from FB Lead Ads field_data array
const fieldData = lead.field_data || [];
const getField = (...names) => {
  for (const name of names) {
    const field = fieldData.find(f =>
      f.name.toLowerCase().includes(name.toLowerCase())
    );
    if (field && field.values && field.values[0]) return field.values[0];
  }
  return '';
};

const name = getField('full_name', 'first_name', 'name');
const email = getField('email');
let phone = getField('phone_number', 'phone', 'mobile');
const courseInterest = getField('course', 'program', 'interested');

// Clean phone number – remove special chars, strip +91 country code
phone = phone.replace(/[\s\-\(\)\+]/g, '');
if (phone.startsWith('91') && phone.length > 10) phone = phone.substring(2);
phone = phone.slice(-10);

// --- AI System Prompt ---
const systemPrompt = [
  'You are a lead qualification AI for an educational institute that offers:',
  '- Professional courses: Data Analytics, Python, MERN, Web Dev, AI/ML, etc.',
  '- Academic tuition: BCA, BSCIT, ICT',
  '',
  'Analyze the lead/message and respond ONLY with valid JSON:',
  '{',
  '  "score": <number 1-10>,',
  '  "classification": "hot_lead" | "warm_lead" | "cold_lead" | "spam" | "not_a_lead",',
  '  "interest_type": "Professional" | "Academic" | "Unknown",',
  '  "course_interest": "<extracted course name or empty>",',
  '  "extracted_name": "<name if mentioned>",',
  '  "reason": "<brief explanation>",',
  '  "suggested_reply": "<brief friendly auto-reply in same language as message>"',
  '}',
  '',
  'Scoring guide:',
  '- 8-10: Clear course interest, real contact info, specific program mentioned',
  '- 5-7: General interest, vague details, might need follow-up',
  '- 3-4: Low quality, incomplete info, unclear intent',
  '- 1-2: Spam, test submission, or clearly not interested',
  '',
  'Note: Messages may be in Hindi, Gujarati, or English. Handle all languages.',
  'Never mention fees in suggested_reply.'
].join('\n');

const userMessage = 'Lead from Facebook Lead Ad form submission:\nName: ' + name + '\nEmail: ' + email + '\nPhone: ' + phone + '\nCourse Interest: ' + courseInterest;

return [{
  json: {
    name,
    email,
    mobile: phone,
    course_interest: courseInterest,
    platform_lead_id: lead.id || '',
    form_id: lead.form_id || '',
    source_detail: 'FB Form: ' + (lead.form_name || lead.form_id || 'Lead Ad'),
    request_body: {
      model: 'llama-3.3-70b-versatile',
      temperature: 0.3,
      max_tokens: 500,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMessage }
      ]
    }
  }
}];

const response = $input.first().json;
const lead = $('Extract & Prepare AI Request').first().json;

let aiText = response.choices?.[0]?.message?.content || '';
aiText = aiText.replace(/```json|```/g, '').trim();

let ai;
try {
  ai = JSON.parse(aiText);
} catch (e) {
  ai = {
    score: 5,
    classification: 'warm_lead',
    interest_type: 'Unknown',
    course_interest: lead.course_interest || '',
    extracted_name: lead.name || '',
    reason: 'AI parse error - defaulting to warm lead',
    suggested_reply: ''
  };
}

const score = Number(ai.score) || 5;

return [{
  json: {
    action: 'create_lead',
    name: ai.extracted_name || lead.name,
    mobile: lead.mobile,
    email: lead.email,
    source: 'Facebook Lead Ad',
    channel_type: 'facebook_leadads',
    entry_type: 'Facebook Lead',
    platform_lead_id: lead.platform_lead_id,
    interest_type: ai.interest_type || 'Unknown',
    course_interest: ai.course_interest || lead.course_interest || '',
    notes: 'AI: ' + (ai.reason || ''),
    ai_score: score,
    ai_classification: ai.classification || 'warm_lead',
    source_detail: lead.source_detail,
    should_create_lead: score >= 3
  }
}];

const body = $input.first().json;

// WhatsApp Cloud API payload structure
const entry = body.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value || {};

// Check if this is a message or just a status update
const messages = value.messages || [];
const statuses = value.statuses || [];
const contacts = value.contacts || [];

if (messages.length === 0 && statuses.length > 0) {
  // This is a delivery status update (sent/delivered/read), not a message
  const status = statuses[0];
  return [{
    json: {
      is_message: false,
      is_status_update: true,
      platform_message_id: status.id || '',
      status: status.status || '',
      recipient_id: status.recipient_id || ''
    }
  }];
}

if (messages.length === 0) {
  return [{ json: { is_message: false, is_status_update: false } }];
}

const msg = messages[0];
const contact = contacts[0] || {};

// Extract message content based on type
let content = '';
let messageType = msg.type || 'text';

if (messageType === 'text') {
  content = msg.text?.body || '';
} else if (messageType === 'image') {
  content = msg.image?.caption || '[Image]';
} else if (messageType === 'video') {
  content = msg.video?.caption || '[Video]';
} else if (messageType === 'audio') {
  content = '[Audio message]';
} else if (messageType === 'document') {
  content = msg.document?.filename || '[Document]';
} else if (messageType === 'location') {
  content = '[Location: ' + (msg.location?.latitude || '') + ',' + (msg.location?.longitude || '') + ']';
} else {
  content = '[' + messageType + ']';
}

return [{
  json: {
    is_message: true,
    is_status_update: false,
    platform_message_id: msg.id || '',
    platform_user_id: msg.from || '',
    sender_name: contact.profile?.name || '',
    content: content,
    message_type: messageType,
    timestamp: msg.timestamp || '',
    phone_number_id: value.metadata?.phone_number_id || ''
  }
}];

