      course_interest: ai.course_interest || '',
      notes: 'AI: ' + (ai.reason || ''),
      ai_score: score,
      ai_classification: ai.classification || 'warm_lead',
      source_detail: 'WhatsApp Inbound Message'
    },
    // Message payload
    message_payload: {
      action: 'create_message',
      platform_user_id: msg.platform_user_id,
      channel_type: 'whatsapp',
      direction: 'inbound',
      message_type: msg.message_type || 'text',
      content: msg.content,
      platform_message_id: msg.platform_message_id,
      sender_name: msg.sender_name || '',
      ai_score: score,
      ai_classification: ai.classification || 'warm_lead'
    },
    // Auto-reply info
    suggested_reply: ai.suggested_reply || '',
    ai_score: score,
    platform_user_id: msg.platform_user_id,
    phone_number_id: msg.phone_number_id
  }
}];

// Handle delivery status updates
const data = $input.first().json;

if (data.is_status_update && data.platform_message_id) {
  return [{
    json: {
      action: 'update_delivery_status',
      platform_message_id: data.platform_message_id,
      status: data.status
    }
  }];
}

// Not a status update and not a message – skip
return [{ json: { action: 'skip', reason: 'Not a message or status update' } }];

const body = $input.first().json;

const entry = body.entry?.[0] || {};
const messaging = entry.messaging?.[0];

if (!messaging || !messaging.message) {
  // Not a message event (could be delivery, read receipt, postback, etc.)
  return [{
    json: {
      is_message: false,
      event_type: messaging?.delivery ? 'delivery' : messaging?.read ? 'read' : 'other'
    }
  }];
}

const senderId = messaging.sender?.id || '';
const recipientId = messaging.recipient?.id || '';
const message = messaging.message || {};

// Detect if this is Instagram or Messenger
// Instagram messages have a different structure and may include
// 'instagram_business_account' in the entry or different ID formats
let channelType = 'messenger';

// Instagram DMs typically come with is_echo or through instagram-specific fields
if (entry.id && messaging.sender && messaging.recipient) {
  // Check for Instagram indicators
  if (body.object === 'instagram' || entry.messaging?.[0]?.sender?.id?.length > 20) {
    channelType = 'instagram';
  }
}

// Extract message content
let content = '';
let messageType = 'text';

if (message.text) {
  content = message.text;
  messageType = 'text';
} else if (message.attachments && message.attachments.length > 0) {
  const attachment = message.attachments[0];
  messageType = attachment.type || 'attachment';
  content = '[' + messageType + ']';
  if (attachment.payload?.url) {
    content += ' ' + attachment.payload.url;
  }
} else if (message.sticker_id) {
  content = '[Sticker]';
  messageType = 'sticker';
}

return [{
  json: {
    is_message: true,
    channel_type: channelType,
    platform_user_id: senderId,
    platform_message_id: message.mid || '',
    content: content,
    message_type: messageType,
    sender_name: '',
    page_id: recipientId,
    timestamp: messaging.timestamp || ''
  }
}];

