const item = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

if (!item.id) {
  return [{ json: { _statusUpdated: false, message: 'No content ID to update' } }];
}

// Fetch all postings for this content item
try {
  const postingsResp = await this.helpers.httpRequest({
    method: 'GET',
    url: CRM + '/api/posting?content_calendar_id=' + item.id,
    headers: headers,
    json: true
  });

  const postings = postingsResp.data || [];
  const postingList = Array.isArray(postings) ? postings : [postings];

  // Check status of each platform
  const getStatus = (platform) => {
    const p = postingList.find(x => x.platform === platform);
    return p ? p.status : 'pending';
  };

  const gbp = getStatus('gbp');
  const ig = getStatus('instagram');
  const li = getStatus('linkedin');
  const pin = getStatus('pinterest');
  const tw = getStatus('twitter');
  const threads = getStatus('threads');

  // Determine overall status
  const autoComplete = ['success', 'manual_backup_sent', 'failed'];
  const manualComplete = ['manual_posted', 'notification_sent'];

  const allDone = autoComplete.includes(gbp) && autoComplete.includes(ig) &&
    (manualComplete.includes(li) || li === 'manual_posted') &&
    autoComplete.includes(pin) &&
    (manualComplete.includes(tw) || tw === 'manual_posted') &&
    (autoComplete.includes(threads) || threads === 'failed');

  const manualPending = (li === 'notification_sent') || (tw === 'notification_sent');

  let newStatus;
  if (li === 'manual_posted' && tw === 'manual_posted') {
    newStatus = 'completed';
  } else if (manualPending) {
    newStatus = 'auto_complete_pending_manual';
  } else {
    newStatus = 'auto_complete_pending_manual';
  }

  await this.helpers.httpRequest({
    method: 'PATCH',
    url: CRM + '/api/content/' + item.id + '/status',
    body: { status: newStatus },
    headers: headers,
    json: true
  });

  return [{ json: { ...item, _calendarStatus: newStatus, _statusUpdated: true } }];
} catch (e) {
  return [{ json: { ...item, _calendarStatus: 'unknown', _statusUpdated: false, _statusError: e.message } }];
}

