const response = $input.first().json;
const data = response.data;

if (!data || (Array.isArray(data) && data.length === 0)) {
  return [{ json: { _hasContent: false } }];
}

// Take first content row
const row = Array.isArray(data) ? data[0] : data;
return [{ json: { ...row, _hasContent: true } }];

const comboResponse = $input.first().json;
const content = $('Check Content Exists').first().json;

// Check if combo was used within 60 days
const comboData = comboResponse.data;
let isBlocked = false;

if (comboData && comboData.last_used_date) {
  const lastUsed = new Date(comboData.last_used_date);
  const now = new Date();
  const daysSinceUsed = Math.floor((now - lastUsed) / (1000 * 60 * 60 * 24));
  isBlocked = daysSinceUsed < 60;
}

return [{ json: { ...content, _isBlocked: isBlocked, _comboData: comboData || {} } }];

const item = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

// 1. PATCH content status → blocked
await this.helpers.httpRequest({
  method: 'PATCH',
  url: CRM + '/api/content/' + item.id + '/status',
  body: { status: 'blocked' },
  headers: headers,
  json: true
});

// 2. POST posting log → blocked
await this.helpers.httpRequest({
  method: 'POST',
  url: CRM + '/api/posting',
  body: {
    content_calendar_id: item.id,
    platform: 'gbp',
    status: 'blocked',
    date: $now.toFormat('yyyy-MM-dd'),
    brand: item.brand,
    content_type: item.content_type,
    content_item: item.topic || '',
    area: item.area_id
  },
  headers: headers,
  json: true
});

// 3. Telegram alert
const tgText = '🚫 Duplicate combo blocked for today:\n' +
  'Brand: ' + item.brand + '\n' +
  'Content: ' + (item.topic || item.content_item_id) + '\n' +
  'Area: ' + item.area_id + '\n' +
  'Date: ' + $now.toFormat('yyyy-MM-dd');

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
  body: { chat_id: $env.TELEGRAM_CHAT_ID, text: tgText },
  json: true
});

return [{ json: { status: 'blocked', message: 'Combo blocked and notified' } }];

const item = $input.first().json;

// Resolve brand settings
let tone, cta;
if (item.brand === 'extrabits_academy') {
  tone = 'warm, educational, outcome-focused';
  cta = 'Visit ExtraBits Academy for a FREE demo class';
} else {
  tone = 'bold, modern, tech-forward, solution-led';
  cta = 'Contact ExtraBits for a free consultation';
}

return [{ json: { ...item, tone: tone, cta: cta } }];

const aiResponse = $input.first().json;
const content = $('Resolve Brand Settings').first().json;

// Parse AI response
let aiText = aiResponse.choices?.[0]?.message?.content || '';
aiText = aiText.replace(/```json|```/g, '').trim();

let captions;
try {
  captions = JSON.parse(aiText);
} catch (e) {
  // Fallback - use master caption for all platforms
  captions = {
    gbp_caption: content.master_caption,
    ig_caption: content.master_caption,
    li_caption: content.master_caption,
    pin_caption: content.master_caption,
    twitter_caption: (content.master_caption || '').substring(0, 275) + '...',
    threads_caption: (content.master_caption || '').substring(0, 395) + '...'
  };
}

// Prepare image URLs from Google Drive share link
const imageUrl = content.image_url || '';
let fileId = '';

// Extract FILE_ID from various Google Drive URL formats
const driveMatch = imageUrl.match(/\/d\/([a-zA-Z0-9_-]+)/);
if (driveMatch) {
  fileId = driveMatch[1];
}

const directImageUrl = fileId
  ? 'https://drive.google.com/uc?export=view&id=' + fileId
  : imageUrl;

const metaImageUrl = directImageUrl;

const proxyMetaImageUrl = fileId
  ? 'https://images.weserv.nl/?url=drive.google.com/uc?id=' + fileId
  : imageUrl;

// Pinterest image: use pin_image_url if available, else direct
const pinterestImageUrl = content.pin_image_url || directImageUrl;

return [{
  json: {
    ...content,
    ...captions,
    direct_image_url: directImageUrl,
    meta_image_url: metaImageUrl,
    proxy_meta_image_url: proxyMetaImageUrl,
    pinterest_image_url: pinterestImageUrl,
    file_id: fileId
  }
}];

const item = $input.first().json;

// Attempt GBP publish
try {
  const gbpResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://mybusiness.googleapis.com/v4/accounts/' + $env.GBP_ACCOUNT_ID + '/locations/' + $env.GBP_LOCATION_ID + '/localPosts',
    body: {
      topicType: 'STANDARD',
      summary: item.gbp_caption,
      media: [{
        mediaFormat: 'PHOTO',
        sourceUrl: item.direct_image_url
      }]
    },
    headers: {
      'Authorization': 'Bearer ' + $vars.GBP_ACCESS_TOKEN,
      'Content-Type': 'application/json'
    },
    json: true
  });

  return [{
    json: {
      ...item,
      gbp_success: true,
      gbp_post_name: gbpResponse.name || '',
      gbp_error: null
    }
  }];
} catch (error) {
  return [{
    json: {
      ...item,
      gbp_success: false,
      gbp_post_name: '',
      gbp_error: error.message || 'GBP publish failed'
    }
  }];
}

