return [{ json: { status: 'success', message: 'GBP published + combo updated + status in_progress' } }];

const item = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

// 1. POST posting log → manual_backup_sent (do NOT update combo)
await this.helpers.httpRequest({
  method: 'POST',
  url: CRM + '/api/posting',
  body: {
    content_calendar_id: item.id,
    platform: 'gbp',
    status: 'manual_backup_sent',
    error: item.gbp_error,
    date: $now.toFormat('yyyy-MM-dd'),
    brand: item.brand,
    content_type: item.content_type,
    content_item: item.topic || '',
    area: item.area_id
  },
  headers: headers,
  json: true
});

// 2. PATCH content status → failed
await this.helpers.httpRequest({
  method: 'PATCH',
  url: CRM + '/api/content/' + item.id + '/status',
  body: { status: 'failed' },
  headers: headers,
  json: true
});

// 3. Telegram backup with caption for manual posting
const tgText = '⚠️ GBP Auto-Post FAILED — ' + $now.toFormat('yyyy-MM-dd') + '\n' +
  'Brand: ' + item.brand + '\n' +
  'Error: ' + (item.gbp_error || 'Unknown') + '\n\n' +
  '--- MANUAL POST CAPTION ---\n' +
  item.gbp_caption + '\n\n' +
  'Image: ' + item.direct_image_url;

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
  body: { chat_id: $env.TELEGRAM_CHAT_ID, text: tgText },
  json: true
});

return [{ json: { status: 'failed', message: 'GBP failed, backup sent via Telegram', error: item.gbp_error } }];

const items = $input.all();
const results = [];

for (const item of items) {
  const body = item.json.body || item.json;
  const message = body.message || body;

  let payload = {};
  if (message && message.data) {
    const decoded = Buffer.from(message.data, 'base64').toString('utf8');
    payload = JSON.parse(decoded);
  } else {
    payload = message;
  }

  results.push({ json: payload });
}

return results;

