const { courses, services, areas, combos } = $input.first().json;

const now = new Date();
const sixtyDaysAgo = new Date(now);
sixtyDaysAgo.setDate(sixtyDaysAgo.getDate() - 60);

// Build blocked set (combos used within last 60 days)
const blockedSet = new Set();
for (const combo of combos) {
  if (combo.last_used_date) {
    const lastUsed = new Date(combo.last_used_date);
    if (lastUsed >= sixtyDaysAgo) {
      blockedSet.add(combo.brand + '_' + combo.content_type + '_' + combo.content_item_id + '_' + combo.area_id);
    }
  }
}

// Build valid Academy pool (course × area, not blocked)
const academyPool = [];
for (const course of courses) {
  for (const area of areas) {
    const key = 'extrabits_academy_course_' + course.id + '_' + area.id;
    if (!blockedSet.has(key)) {
      academyPool.push({
        brand: 'extrabits_academy',
        content_type: 'course',
        content_item_id: course.id,
        content_item_name: course.seo_name || course.course_name || course.name || '',
        short_name: course.short_name || '',
        area_id: area.id,
        area_name: area.area || '',
        seo_name: course.seo_name || ''
      });
    }
  }
}

// Build valid ExtraBits pool (service × area, not blocked)
const extrabitsPool = [];
for (const service of services) {
  for (const area of areas) {
    const key = 'extrabits_service_' + service.id + '_' + area.id;
    if (!blockedSet.has(key)) {
      extrabitsPool.push({
        brand: 'extrabits',
        content_type: 'service',
        content_item_id: service.id,
        content_item_name: service.seo_name || service.service_name || '',
        short_name: service.short_name || '',
        area_id: area.id,
        area_name: area.area || '',
        seo_name: service.seo_name || ''
      });
    }
  }
}

// Shuffle pools
const shuffle = (arr) => {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
};
shuffle(academyPool);
shuffle(extrabitsPool);

// Generate 7 suggestions with brand rotation
// Day 1 (Mon) = Academy, Day 2 (Tue) = ExtraBits, alternating
const monday = new Date(now);
monday.setDate(monday.getDate() + 1); // Sunday → Monday

const suggestions = [];
let academyIdx = 0;
let extrabitsIdx = 0;

for (let day = 0; day < 7; day++) {
  const date = new Date(monday);
  date.setDate(date.getDate() + day);
  const dateStr = date.toISOString().split('T')[0];
  const dayNames = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

  const isAcademy = (day % 2 === 0); // 0,2,4,6 = Academy; 1,3,5 = ExtraBits
  let selected;

  if (isAcademy && academyIdx < academyPool.length) {
    selected = academyPool[academyIdx++];
  } else if (!isAcademy && extrabitsIdx < extrabitsPool.length) {
    selected = extrabitsPool[extrabitsIdx++];
  } else {
    // Fallback: use whatever pool has items
    if (academyIdx < academyPool.length) {
      selected = academyPool[academyIdx++];
    } else if (extrabitsIdx < extrabitsPool.length) {
      selected = extrabitsPool[extrabitsIdx++];
    } else {
      selected = { brand: 'N/A', content_item_name: 'No items available', area_name: '', seo_name: '' };
    }
  }

  // Generate keywords
  let primaryKw, secondaryKw;
  if (selected.brand === 'extrabits_academy') {
    primaryKw = 'best ' + selected.seo_name + ' near ' + selected.area_name + ' in surat';
    secondaryKw = 'best ' + selected.seo_name + ' institute in ' + selected.area_name + ' surat';
  } else {
    primaryKw = 'best ' + selected.seo_name + ' near ' + selected.area_name + ' in surat';
    secondaryKw = 'best ' + selected.seo_name + ' in ' + selected.area_name + ' surat';
  }

  suggestions.push({
    day: day + 1,
    day_name: dayNames[day],
    date: dateStr,
    brand: selected.brand,
    brand_label: selected.brand === 'extrabits_academy' ? 'Academy' : 'ExtraBits',
    content_type: selected.content_type || '',
    content_item_id: selected.content_item_id || '',
    content_item_name: selected.content_item_name || '',
    area_id: selected.area_id || '',
    area_name: selected.area_name || '',
    primary_keyword: primaryKw || '',
    secondary_keyword: secondaryKw || ''
  });
}

return [{ json: {
  monday_date: monday.toISOString().split('T')[0],
  suggestions,
  academy_pool_size: academyPool.length,
  extrabits_pool_size: extrabitsPool.length
} }];

