const data = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

let created = 0;
